import * as React from "react"
import { NavMain } from "./nav-main"
import { NavUser } from "./nav-user"
import { AppSwitcher } from "./app-switcher"
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarRail,
} from "@/components/ui/sidebar"

export interface AppItem {
  name: string
  logo: React.ElementType
  image?: string
  description?: string
  url: string
}

export interface NavItem {
  title: string
  url: string
  icon?: React.ElementType
  isActive?: boolean
  permission?: boolean
  items?: {
    title: string
    url: string
    permission?: boolean
  }[]
}

export interface NavSection {
  sectionName: string
  items: NavItem[]
}

export interface SidebarUser {
  name: string
  email: string
  avatar?: string
}

export interface AppSidebarProps extends React.ComponentProps<typeof Sidebar> {
  apps: AppItem[]
  navSections: NavSection[]
  user: SidebarUser
  onLogout?: () => void
  onSettingsClick?: () => void
}

export function AppSidebar({
  apps,
  navSections,
  user,
  onLogout,
  onSettingsClick,
  ...props
}: AppSidebarProps) {
  return (
    <Sidebar collapsible="icon" {...props}>
      <SidebarHeader className="border-b">
        <AppSwitcher apps={apps} />
      </SidebarHeader>
      <SidebarContent>
        {navSections.map((section) => (
          <NavMain
            key={section.sectionName}
            items={section.items}
            sectionName={section.sectionName}
          />
        ))}
      </SidebarContent>
      <SidebarFooter className="border-t">
        <NavUser
          user={user}
          onLogout={onLogout}
          onSettingsClick={onSettingsClick}
        />
      </SidebarFooter>
      <SidebarRail />
    </Sidebar>
  )
}

"use client"

import * as React from "react"
import { ChevronsUpDown } from "lucide-react"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from "@/components/ui/sidebar"

export interface AppSwitcherItem {
  name: string
  logo: React.ElementType
  image?: string
  description?: string
  url: string
}

export interface AppSwitcherProps {
  apps: AppSwitcherItem[]
  /** Called when the user switches to a different app. If not provided, uses window.location.href. */
  onAppChange?: (app: AppSwitcherItem) => void
}

export function AppSwitcher({ apps, onAppChange }: AppSwitcherProps) {
  const { isMobile } = useSidebar()
  const [activeApp, setActiveApp] = React.useState<AppSwitcherItem>(apps[0])

  const handleAppSelect = (app: AppSwitcherItem) => {
    setActiveApp(app)
    if (onAppChange) {
      onAppChange(app)
    } else {
      window.location.href = app.url
    }
  }

  const Logo = activeApp.logo

  return (
    <SidebarMenu>
      <SidebarMenuItem>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <SidebarMenuButton
              size="lg"
              className="data-[state=open]:bg-sidebar-accent data-[state=open]:text-sidebar-accent-foreground"
            >
              <div className="flex aspect-square size-8 items-center justify-center rounded-lg border">
                {activeApp.image ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img
                    src={activeApp.image}
                    width={20}
                    height={20}
                    alt={activeApp.name}
                    className="size-5 object-contain"
                  />
                ) : (
                  <Logo className="size-4 shrink-0" />
                )}
              </div>
              <div className="grid flex-1 text-left text-sm leading-tight">
                <span className="truncate font-semibold">{activeApp.name}</span>
                {activeApp.description && (
                  <span className="truncate text-xs">{activeApp.description}</span>
                )}
              </div>
              <ChevronsUpDown className="ml-auto" />
            </SidebarMenuButton>
          </DropdownMenuTrigger>
          <DropdownMenuContent
            className="w-[--radix-dropdown-menu-trigger-width] min-w-56 rounded-lg"
            align="start"
            side={isMobile ? "bottom" : "right"}
            sideOffset={4}
          >
            <DropdownMenuLabel className="text-xs text-muted-foreground">
              Apps
            </DropdownMenuLabel>
            {apps
              .filter((app) => app.name !== activeApp.name)
              .map((app, index) => {
                const AppLogo = app.logo
                return (
                  <DropdownMenuItem
                    key={index}
                    onClick={() => handleAppSelect(app)}
                    className="gap-2 p-2"
                  >
                    <div className="flex size-6 items-center justify-center rounded-sm border">
                      {app.image ? (
                        // eslint-disable-next-line @next/next/no-img-element
                        <img
                          src={app.image}
                          width={16}
                          height={16}
                          alt={app.name}
                          className="size-4 object-contain"
                        />
                      ) : (
                        <AppLogo className="size-4 shrink-0" />
                      )}
                    </div>
                    {app.name}
                  </DropdownMenuItem>
                )
              })}
          </DropdownMenuContent>
        </DropdownMenu>
      </SidebarMenuItem>
    </SidebarMenu>
  )
}

"use client"

import { ChevronRight } from "lucide-react"
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible"
import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarMenuSub,
  SidebarMenuSubButton,
  SidebarMenuSubItem,
} from "@/components/ui/sidebar"
import Link from "next/link"
import { usePathname } from "next/navigation"

export interface NavSubItem {
  title: string
  url: string
  permission?: boolean
}

export interface NavMainItem {
  title: string
  url: string
  icon?: React.ElementType
  isActive?: boolean
  permission?: boolean
  items?: NavSubItem[]
}

export interface NavMainProps {
  sectionName: string
  items: NavMainItem[]
}

export function NavMain({ items, sectionName }: NavMainProps) {
  const pathname = usePathname()

  return (
    <SidebarGroup className="px-5 group-data-[collapsible=icon]:px-2">
      <SidebarGroupLabel>{sectionName}</SidebarGroupLabel>
      <SidebarMenu className="gap-2">
        {items.map((item) => {
          const isItemActive = pathname.includes(item.url)
          const activeVariant = isItemActive
            ? "bg-primary text-primary-foreground hover:bg-primary hover:text-primary-foreground active:bg-primary active:text-primary-foreground"
            : "default"

          // Direct link — no sub-items
          if ((!item.items || item.items.length === 0) && item.permission !== false) {
            return (
              <SidebarMenuItem key={item.title}>
                <SidebarMenuButton
                  asChild
                  tooltip={item.title}
                  variant="ghost"
                  className={activeVariant + " h-9"}
                >
                  <Link href={item.url} scroll={true}>
                    {item.icon && <item.icon />}
                    <span>{item.title}</span>
                  </Link>
                </SidebarMenuButton>
              </SidebarMenuItem>
            )
          }

          // Collapsible with sub-items
          if (item.items && item.permission !== false) {
            const isSubActive = item.items.some((subItem) =>
              pathname.includes(subItem.url)
            )
            const collapsibleVariant = isSubActive
              ? "bg-primary text-primary-foreground hover:!bg-primary hover:!text-primary-foreground active:!bg-primary active:!text-primary-foreground"
              : "default"

            return (
              <Collapsible
                key={item.title}
                asChild
                defaultOpen={item.isActive}
                className="group/collapsible"
              >
                <SidebarMenuItem>
                  <CollapsibleTrigger asChild>
                    <SidebarMenuButton
                      tooltip={item.title}
                      className={`${collapsibleVariant} h-9`}
                    >
                      {item.icon && <item.icon />}
                      <span>{item.title}</span>
                      <ChevronRight className="ml-auto transition-transform duration-200 group-data-[state=open]/collapsible:rotate-90" />
                    </SidebarMenuButton>
                  </CollapsibleTrigger>
                  <CollapsibleContent>
                    <SidebarMenuSub className="mr-0 pr-0">
                      {item.items?.map((subItem) => {
                        if (subItem.permission === false) return null
                        const isSubItemActive = pathname.includes(subItem.url)
                        return (
                          <SidebarMenuSubItem key={subItem.title}>
                            <SidebarMenuSubButton
                              asChild
                              className={(isSubItemActive ? "font-bold" : "default") + " h-9"}
                            >
                              <Link href={subItem.url}>
                                <span>{subItem.title}</span>
                              </Link>
                            </SidebarMenuSubButton>
                          </SidebarMenuSubItem>
                        )
                      })}
                    </SidebarMenuSub>
                  </CollapsibleContent>
                </SidebarMenuItem>
              </Collapsible>
            )
          }

          return null
        })}
      </SidebarMenu>
    </SidebarGroup>
  )
}
